mapper.select:
SELECT album.*, first_cover.thumbnail_url AS coverUrl, COALESCE(file_stats.imageCount, 0) AS imageCount, COALESCE(file_stats.videoCount, 0) AS videoCount FROM album LEFT JOIN ( SELECT ap.album_id, file.thumbnail_url, ROW_NUMBER() OVER (PARTITION BY ap.album_id ORDER BY ap.is_cover DESC, ap.id) AS rn FROM album_picture ap JOIN file ON ap.file_id = file.file_id WHERE ap.user_id = #{userId} ) first_cover ON album.album_id = first_cover.album_id AND first_cover.rn = 1 LEFT JOIN ( SELECT ap.album_id, COUNT(CASE WHEN f.category = 'image' THEN 1 END) AS imageCount, COUNT(CASE WHEN f.category = 'video' THEN 1 END) AS videoCount FROM album_picture ap JOIN file f ON ap.file_id = f.file_id WHERE ap.user_id = #{userId} GROUP BY ap.album_id ) file_stats ON album.album_id = file_stats.album_id
album.user_id = #{userId}
ORDER BY
album.${orderKeyword}
album.create_time
${orderType}
DESC

SELECT file.*, DATE(${orderKeyword}) AS group_date, video_meta_data.duration AS duration FROM file INNER JOIN user_file uf ON file.file_id = uf.file_id LEFT JOIN video_meta_data ON file.file_id = video_meta_data.file_id
uf.is_deleted = #{isDeleted} AND uf.user_id = #{userId}
AND file.make = #{makeName}
AND file.model = #{modelName}
AND file.category = 'image' AND file.content_type != 'image/gif'
AND file.content_type = 'image/gif'
AND file.category = 'video'
GROUP BY uf.user_id, file.file_id, DATE(${orderKeyword})
GROUP BY uf.user_id, file.file_id
ORDER BY
${orderKeyword} ${orderType}
${orderKeyword} DESC

SELECT file.*, DATE(${orderKeyword}) AS group_date, video_meta_data.duration AS duration FROM file INNER JOIN user_file uf ON file.file_id = uf.file_id LEFT JOIN video_meta_data ON file.file_id = video_meta_data.file_id INNER JOIN face ON file.file_id = face.file_id AND face.user_id = #{userId} INNER JOIN person_face pf ON face.face_id = pf.face_id AND pf.user_id = #{userId}
uf.is_deleted = #{isDeleted} AND uf.user_id = #{userId} AND pf.person_id = #{personId}
AND file.category = 'image' AND file.content_type != 'image/gif'
AND file.content_type = 'image/gif'
AND file.category = 'video'
GROUP BY uf.user_id, file.file_id, DATE(${orderKeyword})
GROUP BY uf.user_id, file.file_id
ORDER BY
${orderKeyword} ${orderType}
${orderKeyword} DESC

